%[text] # 배열 행렬 만들기
%[text] 이름: 양연우
%[text] - 벡터와 행렬을 만드는 방법
%[text] - 행렬 연산
%[text] - 행렬의 일부
%[text] - 그래프
%[text] - 소리 파일 다루기 \
%%
%[text] ## 간단한 배열
%[text] - 벡터: 열벡처, 행벡터
%[text] - 행렬: 2차원 배열 \
m = [1 4 2 5] % 행 벡터, row vector %[output:921ed5af]
v = [1; 6; -1; 3] % 열 벡터, column vector %[output:52ebe6f4]
M = [1 3 5 7; 2 4 6 8] %[output:1fdb4935]
m = M(2,2) %[output:44125d0e]
%%
%[text] ### 행렬의 크기
%[text] - 명령어: size(nxn을 나타냄), length(가장 긴 길이를 나타냄), numel(요소의 개수) \
M %[output:9a40f18a]
whos M %[output:497d6acf]
[nRows, nCols] = size(M) %[output:2cd8ae75] %[output:20ed882b]
nCol = size(M,2) %[output:148b9904]
nRow = size(M,1) %[output:5d7d4e4c]
N = M' %[output:630eacfe]
ln = length(N) %[output:25042f9c]
kk = numel(M) %[output:2559d99c]
%%
%[text] ### 그래프
%[text] - 명령어: plot(선그래프 그리는 함수), stem(줄기처럼 생긴 그래프), bar() \
v %[output:8d1a2456]
h = plot(v,'g--o', "MarkerFaceColor", "g")%% (함수v를, '빨간 선으로 꺾이는 지점을 원으로 표시하라', "면을 채워라", "빨간색으로") %[output:7c383a41] %[output:56e65762]
h. LineWidth =2; %[output:56e65762]
grid on; %% 격자 %[output:56e65762]
xlabel("$x$", "Interpreter","latex"); ylabel("y") %[output:56e65762]
%[text] 'r-o': 실선 / 'r--o':  점선 / h=:  속성 / LineWidth: 라인의 굵기 수치로 조절 / xlabel(""): ""내용을 x축의 라벨로 삼음 ylabel(""): xlabel =
%%
%[text] stem 그래프
stem(v, 'r', 'filled') %[output:6fbfaa6e]
grid; %[output:6fbfaa6e]
xlabel("value"); ylabel("measured") %[output:6fbfaa6e]
%%
%[text] bar: 막대 그래프
bar(v, "FaceColor", "g") %[output:3c2f2370]
legend("Income") %% 그래프 내에 정보 입력 %[output:3c2f2370]
%[text] 
